// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const currentQuestionResult = $('Compare answers').first().json.is_correct ? 1 : 0;

const previousScore = $('Get quiz_session from DB').first().json.score;

const finalScore = currentQuestionResult + previousScore;

const answers = $("Get quiz results from DB").all();

const results = [];

for (const item of $input.all()) {
  const actualAnswer = answers.find(x => x.json.quiz_id == item.json.id);
  const actualAnswerLetter = actualAnswer.json.selected_answer;

  var res = {
    q: 'Q' + item.json.question_index + ': ' + item.json.question,
    yourAnswer: item.json.options[actualAnswerLetter],
    correctAnswer: item.json.options[item.json.correct_answer],
    explanation: item.json.explanation
  }

  results.push(res);
}

return {
  results: results,
  finalScore: finalScore
}

function newGuid() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'
    .replace(/[xy]/g, c => {
      const r = Math.floor(Math.random() * 16);
      const v = c === 'x'
        ? r
        : (r & 0x3) | 0x8;

      return v.toString(16);
    });
}

return {generatedGuid: newGuid()};
